class Solution:
    def isValidSudoku(self, board):
        def dup(cells):
            vals = [v for v in cells if v != '.']
            return len(vals) != len(set(vals))
        for r in range(9):
            if dup(board[r]):
                return False
        for c in range(9):
            if dup([board[r][c] for r in range(9)]):
                return False
        for br in range(0, 9, 3):
            for bc in range(0, 9, 3):
                cells = [board[br + i][bc + j] for i in range(3) for j in range(3)]
                if dup(cells):
                    return False
        return True

